class Solution {
public:
    int minimumOneBitOperations(int n) {
        int res = 0, sign = 1;
        while (n) {
            res += sign * (n ^ (n - 1));
            sign = -sign;
            n &= n - 1;
        }
        return abs(res);
    }
};
